import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
GRID = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_model_files(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    names = [
        "config.json",
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
        "model-00001-of-00002.safetensors",
    ]
    return any((path / n).exists() for n in names)


def _read_json(path: Path) -> Dict:
    try:
        return json.loads(path.read_text())
    except Exception:
        return {}


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt = Path(checkpoint).resolve()
    ckpt_dir = ckpt if ckpt.is_dir() else ckpt.parent
    meta = _read_json(ckpt_dir / "meta.json")
    cwd = Path.cwd().resolve()
    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        cwd / "checkpoints" / ckpt_dir.name / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        Path("/workspace/checkpoints") / ckpt_dir.name / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
    ]
    for key in ["base_model_dir", "base_model", "base_dir"]:
        val = meta.get(key)
        if val:
            p = Path(val)
            candidates.append(p if p.is_absolute() else (ckpt_dir / p).resolve())
            candidates.append(p if p.is_absolute() else (cwd / p).resolve())
    seen = set()
    for c in candidates:
        s = str(c)
        if s in seen:
            continue
        seen.add(s)
        if _has_model_files(c):
            return s
    raise FileNotFoundError(f"Could not locate base model for checkpoint: {checkpoint}")


def load_processor(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt = Path(checkpoint).resolve()
    base = Path(resolve_base_model_dir(checkpoint))
    cands = []
    if (ckpt / "processor").exists():
        cands.append(ckpt / "processor")
    cands.append(ckpt)
    cands.append(base)
    last_err = None
    for c in cands:
        try:
            return AutoProcessor.from_pretrained(
                str(c),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
        except Exception as e:
            last_err = e
    raise last_err


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    base = resolve_base_model_dir(checkpoint)
    processor = load_processor(checkpoint, min_pixels=min_pixels, max_pixels=max_pixels)
    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    ckpt_dir = Path(checkpoint).resolve()
    if (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    prompt = (
        "Identify the UI target described by the instruction. "
        "Reply with only one point on a 0-1000 by 0-1000 grid in the format <point>x y</point>. "
        "Do not output any explanation.\n"
        f"Instruction: {instruction}"
    )
    return [{"role": "user", "content": [{"type": "image"}, {"type": "text", "text": prompt}]}]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def parse_prediction_text(raw_text: str) -> Optional[ParsedPrediction]:
    if raw_text is None:
        return None
    text = raw_text.strip()
    if not text:
        return None

    m = re.search(r"<point>\s*([^<]+?)\s*</point>", text, flags=re.I | re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 2:
            if len(nums) >= 4:
                x1, y1, x2, y2 = nums[:4]
                cx = (x1 + x2) / 2.0
                cy = (y1 + y2) / 2.0
                return ParsedPrediction("point", [cx, cy], raw_text=text)
            return ParsedPrediction("point", nums[:2], raw_text=text)

    m = re.search(r"<box>\s*([^<]+?)\s*</box>", text, flags=re.I | re.S)
    if m:
        nums = _extract_numbers(m.group(1))
        if len(nums) >= 4:
            x1, y1, x2, y2 = nums[:4]
            cx = (x1 + x2) / 2.0
            cy = (y1 + y2) / 2.0
            return ParsedPrediction("point", [cx, cy], raw_text=text)

    nums = _extract_numbers(text)
    if len(nums) >= 4:
        x1, y1, x2, y2 = nums[:4]
        cx = (x1 + x2) / 2.0
        cy = (y1 + y2) / 2.0
        return ParsedPrediction("point", [cx, cy], raw_text=text)
    if len(nums) >= 2:
        return ParsedPrediction("point", nums[:2], raw_text=text)
    return None


def _clip(v: float, lo: float, hi: float) -> float:
    return float(max(lo, min(hi, v)))


def _grid_to_abs_point(x: float, y: float, w: float, h: float):
    return [_clip(x / GRID * w, 0.0, w), _clip(y / GRID * h, 0.0, h)]


def generate_raw(model, processor, image, instruction: str, max_new_tokens: int = 16) -> str:
    messages = build_messages(instruction)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(text=[text], images=[image], return_tensors="pt")
    inputs = {k: v.to(model.device) if hasattr(v, "to") else v for k, v in inputs.items()}
    with torch.no_grad():
        out = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    prompt_len = inputs["input_ids"].shape[1]
    gen_ids = out[:, prompt_len:]
    raw = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return raw.strip()


def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float):
    try:
        raw = generate_raw(model, processor, image, instruction)
        parsed = parse_prediction_text(raw)
        if parsed is not None and len(parsed.values) >= 2:
            x, y = parsed.values[:2]
            pt = _grid_to_abs_point(x, y, float(image_width), float(image_height))
            return {"point": pt, "raw": raw}
    except Exception:
        pass
    return {"point": [float(image_width) / 2.0, float(image_height) / 2.0], "raw": ""}
